public class Main {
    public static void main(String[] args) {

        int   secret   = 42;
        int[] guesses  = {15, 80, 42};
        int   idx      = 0;
        int   attempts = 0;

        while (idx < guesses.length) {
            int guess = guesses[idx];
            idx++;
            attempts++;

            if (guess < secret) {
                System.out.println("Guess " + guess + ": Too low");
            } else if (guess > secret) {
                System.out.println("Guess " + guess + ": Too high");
            } else {
                System.out.println("Guess " + guess + ": Correct in " + attempts + " attempt(s)!");
                break;
            }
        }
    }
}

